const express = require('express');
const morgan = require('morgan');
const fs = require('fs');
const path = require('path');

const app = express();
const port = 3000;

// Create a write stream for logging
const logStream = fs.createWriteStream(path.join(__dirname, 'access.log'), { flags: 'a' });

// Custom logging format
morgan.format('custom', ':remote-addr :method :url :status :res[content-length] - :response-time ms :req[header-name] :req[username]');

// Use morgan middleware to log requests
app.use(morgan('custom', {
  stream: logStream,
  skip: (req, res) => res.statusCode < 400 // Optionally log only if status code >= 400
}));

app.use(express.json());
app.use(express.urlencoded({ extended: true }));

app.post('/log', (req, res) => {
  const { username, headerName } = req.body;
  const ip = req.ip;

  if (username) {
    console.log(`User: ${username}, IP: ${ip}, Header: ${headerName}`);
  }

  res.send('Data logged');
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}`);
});